package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.bv.BerekenVerminderingBvWerkbonus;
import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvPensioenZorgSector;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.OpdrachtenGroepBuilder;
import be.schaubroeck.lpb.rkm.rekenmotor.util.OpdrachtenGroepBuilder.BvcumulGewoneBezoldigingCriterium;
import be.schaubroeck.lpb.rkm.rekenmotor.util.OpdrachtenGroepBuilder.OpdrachtGroep;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.SleutelGegevensSingleOpper;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.GewWrkwBv;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import lombok.extern.slf4j.Slf4j;

import java.math.BigDecimal;
import java.util.Collection;
import java.util.List;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOONSDATA_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PRESTATIEVERHOUDING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REGUL_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.SCHOOLVERLATER_KEY;

@Slf4j
public class BerekenBvGewoon extends AbstractBerekenBv {

    private static final OpdrachtGroepCriterium BV_GEWONE_BEZOLDIGINGEN_CRITERIUM = BvcumulGewoneBezoldigingCriterium.INSTANCE;

    private BvPensioenZorgSector bvPensioenZorgSector = null;
    private BerekenVerminderingBvWerkbonus berekenVerminderingBvWerkbonus = null;

    public BerekenBvGewoon(ConstantManager constantManager, NlpGlobalService service) {
        super(constantManager, service);
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        initFiscaleConstanten(rekenTijd);
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        OpdrachtenGroepBuilder groeper = new OpdrachtenGroepBuilder();
        List<OpdrachtGroep> opdrachtGroepen = groeper.groepeer(persoon, BV_GEWONE_BEZOLDIGINGEN_CRITERIUM, rekenTijd);
        for (OpdrachtGroep opdrachtGroep : opdrachtGroepen) {
            berekenBVGewoneBezoldiging(mainContext, persoon, opdrachtGroep);
        }
        berekenVerminderingBvWerkbonus.bereken(mainContext, rekenTijd);
        bvPensioenZorgSector.behandel(mainContext);
        bvVoluntariaat.minimaalVoluntariaat(mainContext);
        return CONTINUE_PROCESSING;
    }

    @Override
    public void initFiscaleConstanten(RekenTijd rekenTijd) {
        super.initFiscaleConstanten(rekenTijd);
        this.bvPensioenZorgSector = new BvPensioenZorgSector(BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY, taxdatum, constantManager);
        this.berekenVerminderingBvWerkbonus = BerekenVerminderingBvWerkbonus.builder()
                .fiscaleConstanten(fiscaleConstanten)
                .bvVoluntariaat(bvVoluntariaat)
                .taxdatum(taxdatum)
                .build();
    }

    /* Voor berekening BAREMA_KUMUL zijn er (minstens) twee interpretaties mogelijk.
     * Optie 1 vlag gepensioneerd is true als één van de opdrachten een hoedanigheid gepensioneerd is.
     * Optie 2 vlag gepensioneerd is true als alle van de opdrachten een hoedanigheid gepensioneerd zijn.
     * Optie 3 Bv wordt apart berekend (wel met gekumuleerd belastbaar), de twee BV's zullen dan wel niet consistent zijn.
     * voorlopig optie 1.
     */
    private boolean berekeningIsGepensioneerd(OpdrachtGroep opdrachtGroep) {
        boolean isGepensioneerd = false;
        for (Opdracht opdracht : opdrachtGroep.getOpdrachten()) {
            Hoedanigheid hoedanigheid = opdracht.getHoedanigheid();
            if (hoedanigheid == Hoedanigheid.MANDATARISSEN_GEPENSIOENEERD || hoedanigheid == Hoedanigheid.WERKNEMERS_GEPENSIOENEERD) {
                isGepensioneerd = true;
                break;
            }
        }
        return isGepensioneerd;
    }

    public void berekenBVGewoneBezoldiging(RekenContext context, Persoon persoon, OpdrachtGroep opdrachtGroep) {
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);

        Collection<LoonElement> loonElementen = LoonElement.createSortedSet();
        for (Opdracht opdracht : opdrachtGroep.getOpdrachten()) {
            RekenContext opdrachtContext = context.getOpdrachtContext(opdracht);
            if (!opdrachtContext.getBoolean(SCHOOLVERLATER_KEY)) {
                loonElementen.addAll(manager.getOpdrachtsElementen(opdracht));
            }
        }
        Money belastbaar = getBelastbaar(BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY, BELASTBAAR_KEY, loonElementen);

        if (belastbaar.signum() > 0 && !opdrachtGroep.uitzonderingJobStudent(context.getRekenTijd())) {
            GewWrkwBv fiscaleWerkwijze = opdrachtGroep.getWerkwijzeGewoneBezoldiging();
            switch (fiscaleWerkwijze) {
                case BAREMA_GN_KUMUL:
                case BAREMA_KUMUL:
                    werkwijzeBarema(context, persoon, opdrachtGroep, loonElementen, belastbaar);
                    break;
                case BAREMA_INV_PVH:
                    werkwijzeBaremaInvPvh(context, persoon, opdrachtGroep, loonElementen, belastbaar);
                    break;
                case PERCENTAGE:
                case BEDRAG:
                    werkwijzeGeenBarema(context, opdrachtGroep, loonElementen, belastbaar, fiscaleWerkwijze);
                    break;
                default:
                    RegulManager regulManager = context.getUnchecked(REGUL_MANAGER_KEY);
                    regulManager.doRegulException(null, Regulkode.NIET_GEPROGRAMMEERD);
            }
        }
    }

    private void werkwijzeBarema(
            RekenContext context, Persoon persoon, OpdrachtGroep opdrachtGroep, Collection<LoonElement> loonElementen,
            Money belastbaar) {
        RegulManager regulManager = context.getUnchecked(REGUL_MANAGER_KEY);
        boolean isStagairVastbenoemd = berekeneningIsStagairVastbenoemd(context, opdrachtGroep);
        boolean gepensioneerd = berekeningIsGepensioneerd(opdrachtGroep);
        boolean heeftBrugPensioen = loonElementen.stream().map(LoonElement::getAardKodeExtensie).anyMatch(LoonCodeTools::isBrugPensioen);
        gepensioneerd = gepensioneerd || heeftBrugPensioen;
        RekenTijd rekenTijd = context.getUnchecked(REKENTIJD_KEY);
        Money bedrijfsvoorheffing =
                berekenBVGewoneBezoldigingBarema(persoon, belastbaar, gepensioneerd, isStagairVastbenoemd, rekenTijd, regulManager);
        herverdeelBedrijfsvoorheffing(BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY, bedrijfsvoorheffing, BELASTBAAR_KEY, belastbaar, loonElementen);

        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        for (Opdracht opdracht : opdrachtGroep.getOpdrachten()) {
            RekenContext opdrachtContext = context.getOpdrachtContext(opdracht);
            if (!opdrachtContext.getBoolean(SCHOOLVERLATER_KEY)) {
                Collection<LoonElement> opdrachtElementen = manager.getOpdrachtsElementen(opdracht);
                Money bvOpdracht = RekenTools.getSomProperty(BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY, opdrachtElementen);
                Money bbOpdracht = getBelastbaar(BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY, BELASTBAAR_KEY, opdrachtElementen);
                log.debug("bedrijfsvoorheffing:{}", bedrijfsvoorheffing);

                Money voluntariaat = bvVoluntariaat.bepaalGewoon(opdrachtContext, opdrachtElementen);
                bvOpdracht = bvOpdracht.add(voluntariaat);
                herverdeelBedrijfsvoorheffing(BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY, bvOpdracht, BELASTBAAR_KEY, bbOpdracht, opdrachtElementen);
            }
        }
    }

    private void werkwijzeBaremaInvPvh(
            RekenContext context, Persoon persoon, OpdrachtGroep opdrachtGroep, Collection<LoonElement> loonElementen,
            Money belastbaar) {
        RegulManager regulManager = context.getUnchecked(REGUL_MANAGER_KEY);
        boolean isStagairVastbenoemd = berekeneningIsStagairVastbenoemd(context, opdrachtGroep);
        boolean gepensioneerd = berekeningIsGepensioneerd(opdrachtGroep);
        boolean heeftBrugPensioen = loonElementen.stream().map(LoonElement::getAardKodeExtensie).anyMatch(LoonCodeTools::isBrugPensioen);
        gepensioneerd = gepensioneerd || heeftBrugPensioen;
        Opdracht opdracht = opdrachtGroep.getOpdracht();
        RekenContext opdrachtContext = context.getOpdrachtContext(opdracht);
        if (!opdrachtContext.getBoolean(SCHOOLVERLATER_KEY)) {
            Opper opperLaatsteGegevens = opdrachtContext.getUnchecked(OPPER_LAATSTE_GEGEVENS_KEY);
            BigDecimal prestatieVerhouding = opdrachtContext.getDoubleKey(PRESTATIEVERHOUDING_KEY, opperLaatsteGegevens);
            if (prestatieVerhouding.signum() == 0) {
                prestatieVerhouding = BigDecimal.ONE;
                regulManager.doRegulException(opdracht, Regulkode.BASISBETAALBREUK_NUL);
            }
            Money belastbaarInvPvh = belastbaar.divide(prestatieVerhouding);
            RekenTijd rekenTijd = context.getUnchecked(REKENTIJD_KEY);
            Money bvOpdracht =
                    berekenBVGewoneBezoldigingBarema(persoon, belastbaarInvPvh, gepensioneerd, isStagairVastbenoemd, rekenTijd, regulManager);

            bvOpdracht = bvOpdracht.multiply(prestatieVerhouding);
            Money voluntariaat = bvVoluntariaat.bepaalGewoon(opdrachtContext, loonElementen);
            bvOpdracht = bvOpdracht.add(voluntariaat);
            herverdeelBedrijfsvoorheffing(BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY, bvOpdracht, BELASTBAAR_KEY, belastbaar, loonElementen);

        }
    }

    private void werkwijzeGeenBarema(
            RekenContext context, OpdrachtGroep opdrachtGroep, Collection<LoonElement> loonElementen, Money belastbaar,
            GewWrkwBv fiscaleWerkwijze) {
        Opdracht opdracht = opdrachtGroep.getOpdracht();
        RekenContext opdrachtContext = context.getOpdrachtContext(opdracht);
        if (!opdrachtContext.getBoolean(SCHOOLVERLATER_KEY)) {
            Opper opperLaatsteGegevens = opdrachtContext.getUnchecked(OPPER_LAATSTE_GEGEVENS_KEY);
            Money bvOpdracht = Money.ZERO;
            if (fiscaleWerkwijze == GewWrkwBv.PERCENTAGE) {
                BigDecimal bvPercentageNormaal = opperLaatsteGegevens.getOpdrachtFiscaliteit().getPercentageGewoneBezoldiging().movePointLeft(2);
                bvOpdracht = belastbaar.multiply(bvPercentageNormaal).round(2);
            } else if (fiscaleWerkwijze == GewWrkwBv.BEDRAG) {
                bvOpdracht = opperLaatsteGegevens.getOpdrachtFiscaliteit().getBedragGewoneBezoldiging();
            }
            Money voluntariaat = bvVoluntariaat.bepaalGewoon(opdrachtContext, loonElementen);
            bvOpdracht = bvOpdracht.add(voluntariaat);
            herverdeelBedrijfsvoorheffing(BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY, bvOpdracht, BELASTBAAR_KEY, belastbaar, loonElementen);
        }
    }

    private boolean berekeneningIsStagairVastbenoemd(RekenContext context, OpdrachtGroep opdrachtGroep) {
        PersoonsDataManager dataManager = context.getUnchecked(PERSOONSDATA_MANAGER_KEY);
        RekenTijd rekentijd = context.getUnchecked(REKENTIJD_KEY);
        Persoon persoon = dataManager.getPersoonOpDatum(rekentijd.eindDatum, true);
        OpdrachtenGroepBuilder groeper = new OpdrachtenGroepBuilder();
        List<OpdrachtGroep> opdrachtGroepen = groeper.groepeer(persoon, BV_GEWONE_BEZOLDIGINGEN_CRITERIUM, rekentijd);
        OpdrachtGroep gezocht =
                opdrachtGroepen.stream().filter(x -> x.getSleutel().equals(opdrachtGroep.getSleutel())).findFirst().orElse(opdrachtGroep);
        boolean isStagairVastbenoemd = false;
        for (Opdracht opdracht : gezocht.getOpdrachten()) {
            Opper opperLaatsteGegevens = RekenTools.getOpperLaatsteGegevens(opdracht);
            isStagairVastbenoemd = RekenTools.isStagairVastbenoemd(rekentijd, new SleutelGegevensSingleOpper(opperLaatsteGegevens));
            if (isStagairVastbenoemd) {
                break;
            }
        }
        return isStagairVastbenoemd;
    }
}
